CustomField.formula:
if(Normalized_Phone_Length__c = 10, Normalized_Phone__c, 
  if(AND(Normalized_Phone_Length__c > 10,
     LEFT(Normalized_Phone__c, 1)="1"),
          LEFT(TRIM(Right(Normalized_Phone__c, Normalized_Phone_Length__c -1)),10),
     if(Normalized_Phone_Length__c > 10,
      LEFT(Normalized_Phone__c, 10), "")))
